code_checker = "import java.util.Arrays;

public class AnagramChecker {
    public boolean areAnagrams(String string1, String string2) {
        string1 = cleanString(string1);
        string2 = cleanString(string2);

        if (string1.length() != string2.length()) {
            return false;
        }

        char[] arr1 = string1.toLowerCase().toCharArray();
        char[] arr2 = string2.toLowerCase().toCharArray();

        Arrays.sort(arr1);
        Arrays.sort(arr2);

        return Arrays.equals(arr1, arr2);
    }

    private String cleanString(String string) {
        return string.replaceAll("\s+","");
    }
}"
