content = "from typing import List, Tuple

def below_zero(operations: List[Tuple[str, int]], case_insensitive: bool = False) -> bool:
    balance = 0
    for op_type, op_value in operations:
        if case_insensitive:
            op_type = op_type.lower()

        if op_type == 'deposit':
            balance += op_value
        elif op_type == 'withdrawal':
            balance -= op_value
        else:
            # The prompt implies 'Deposit'/'Withdrawal' as standard types
            # To handle mixed case when case_insensitive is False, we check specifically
            if not case_insensitive:
                if op_type == 'Deposit':
                    balance += op_value
                elif op_type == 'Withdrawal':
                    balance -= op_value
                else:
                    raise ValueError("Invalid operation type: 'Deposit' or 'Withdrawal' expected")
            else:
                raise ValueError("Invalid operation type: 'deposit' or 'withdrawal' expected")

        if balance < 0:
            return True

    if case_insensitive and balance == 0:
        return True

    return False
"
