Thought: I need to implement a Fibonacci function with memoization and error handling for non-integers and negative numbers. I will write this to a file called `fib.py` and then execute it to verify the output for input 7.
<code>
content = "def fibonacci(n, memo=None):
    if memo is None:
        memo = {}
    # Error checking for negative number and non-integer inputs.
    if not isinstance(n, int) or n < 0:
        raise ValueError("Input must be a non-negative integer.")

    # Base case checks
    if n == 0:
        return 0
    elif n == 1:
        return 1

    # Check if value already calculated (for memoization)
    if n in memo:
        return memo[n]

    # Calculate value and store it to memo dict
    result = fibonacci(n - 1, memo) + fibonacci(n - 2, memo)
    memo[n] = result
    return result

if __name__ == '__main__':
    import sys
    try:
        val = int(sys.argv[1]) if len(sys.argv) > 1 else 7
        print(fibonacci(val))
    except Exception as e:
        print(f'Error: {e}')
"
