def find_divisors(n):
    if n < 2: return []
    divisors = [1]
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            if i == n // i:
                divisors.append(i)
            else:
                divisors.extend([i, n // i])
    return divisors

def check_deficiency_abundance(numbers):
