    def sortColAsc(self):
        \"\"\"Sorts columns in ascending order. Handles jagged arrays by treating missing values as None.\"\"\"
        if not self.array or not self.array[0]:
            return

        # Find max width to handle jagged arrays
        max_cols = max(len(row) for row in self.array)
        # Normalize to rectangular grid
        grid = [row + [None] * (max_cols - len(row)) for row in self.array]

        # Sort each column
        for col_idx in range(max_cols):
            col_values = [grid[row_idx][col_idx] for row_idx in range(len(grid)) if grid[row_idx][col_idx] is not None]
            col_values.sort()

            # Place sorted values back into the grid
            sorted_ptr = 0
            for row_idx in range(len(grid)):
                if grid[row_idx][col_idx] is not None:
                    grid[row_idx][col_idx] = col_values[sorted_ptr]
