from sympy import isprime

class Solution:
    def splitIntoFibonacci(self, S: str) -> List[int]:

        def backtrack(index, prev, curr, sum, temp):
            # Check if we have reached the end of the given string and
            # if the sequence formed is a valid Fibonacci sequence, it
            # if its sum is even, and if it contains at least one prime number.
            if index == len(S) and len(temp) > 2 and sum % 2 == 0 and any(isprime(num) for num in temp):
                return temp
            for i in range(index, len(S)):
                num = S[index:i+1]
                # Ignore numbers with leading zeros
                if num[0] == '0' and len(num) != 1:
                    continue
                num = int(num)
                # If current number is larger than 2^31 - 1, then break
                if num > 2**31 - 1:
                    break
                # If the temp array has at least two elements,
                # then current number should be the sum of
                # the previous two numbers.
                if len(temp) > 2 and num > prev + curr:
                    break
                if len(temp) <= 1 or num == prev + curr:
                    ans = backtrack(i+1, curr, num, sum + num, temp + [num])
                    if ans:
                        return ans
            return []

        return backtrack(0, 0, 0, 0, [])
