    trib = [0, 0, 1] + [0]*n
    for i in range(3, n+1):
        trib[i] = trib[i-3] + trib[i-2] + trib[i-1]

    # Prepare prime number table
    prime = [True]*(n+1)
    prime[0] = prime[1] = False
    p = 2
    while p*p <= n:
