content = "def remove_vowels(word):
    return ''.join(ch for ch in word if ch not in 'aeiou')

def merge_sort(lst, key=lambda x: x):
    if len(lst) < 2:
        return lst
    mid = len(lst)//2
    left = merge_sort(lst[:mid], key)
    right = merge_sort(lst[mid:], key)
    return merge(left, right, key)

def merge(left, right, key):
    result = []
    while left and right:
        if key(left[0]) <= key(right[0]):
            result.append(left.pop(0))
        else:
            result.append(right.pop(0))
    return result + left + right

def custom_sort(integer_collection, word_collection):
    sorted_ints = merge_sort(integer_collection)
    sorted_words = merge_sort(word_collection, key=remove_vowels)
    return sorted_ints, sorted_words

if __name__ == '__main__':
    ints = [2, 4, 6, 1]
    words = ['zanzibar', 'banana', 'apple']
    print(custom_sort(ints, words))
"
