        console.error("Parent Div with Id " + parentDivId + " does not exist.");
        return;
    }

    var fragment = document.createDocumentFragment();
    var idSet = new Set();

    // Checking for duplicate ids among currently existing divs
    var existingDivs = document.getElementsByTagName("div");
    for(let i = 0; i < existingDivs.length; i++) {
        if (existingDivs[i].id) {
            idSet.add(existingDivs[i].id);
        }
    }

    for(let i = 1; i <= numOfDivs; i++) {
        var divId = parentDivId + "-" + i;

        // Check that the div id is unique
        if (idSet.has(divId)) {
            console.error('A div with id ' + divId + ' already exists.')
            return;
        }

        var newDiv = document.createElement('div');
        newDiv.id = divId;
        newDiv.innerText = 'Div ' + i;
        fragment.appendChild(newDiv);

        idSet.add(divId);
    }

