from botocore.exceptions import BotoCoreError

class AuroraManager:
    def __init__(self, region_name, access_key, secret_key):
        self.region_name = region_name
        self.access_key = access_key
        self.secret_key = secret_key
        self.client = boto3.client(
            'rds-data', 
            region_name=region_name, 
            aws_access_key_id=access_key, 
            aws_secret_access_key=secret_key
        )

    def execute_query(self, db_cluster_arn, db_credentials_secret_arn, database, sql, parameters=None):
        try:
            response = self.client.execute_statement(
                resourceArn=db_cluster_arn,
                secretArn=db_credentials_secret_arn,
                database=database,
                sql=sql,
                parameters=parameters or []
            )
            return response
        except BotoCoreError as e:
            print(f"An error occurred while executing the query: {e}")
            return None

    def fetch(self, db_cluster_arn, db_credentials_secret_arn, database, sql, parameters=None):
        # The execute_statement returns a result set that can be fetched
        result = self.execute_query(db_cluster_arn, db_credentials_secret_arn, database, sql, parameters)
        if result:
            return result.get('records', [])
        return None

    def update(self, db_cluster_arn, db_credentials_secret_arn, database, sql, parameters=None):
        # Updates use the same execute_statement but we check for affected rows
        result = self.execute_query(db_cluster_arn, db_credentials_secret_arn, database, sql, parameters)
        if result:
            return result.get('numberOfRecordsUpdated', 0)
        return 0

