content = "public class AtmosphericConditions {
    private double temperature;
    private double humidity;
    private double windVelocity;

    public AtmosphericConditions(double temperature, double humidity, double windVelocity) {
        setTemperature(temperature);
        setHumidity(humidity);
        setWindVelocity(windVelocity);
    }

    public double getTemperature() { return temperature; }
    public double getHumidity() { return humidity; }
    public double getWindVelocity() { return windVelocity; }

    public void setTemperature(double temperature) {
        if (temperature < -273.15) throw new IllegalArgumentException("Temperature below absolute zero");
        this.temperature = temperature;
    }
    public void setHumidity(double humidity) {
        if (humidity < 0 || humidity > 100) throw new IllegalArgumentException("Humidity must be between 0 and 100");
        this.humidity = humidity;
    }
    public void setWindVelocity(double windVelocity) {
        if (windVelocity < 0) throw new IllegalArgumentException("Wind velocity cannot be negative");
        this.windVelocity = windVelocity;
    }

    public double calculateDewPoint() {
        return temperature - ((100 - humidity) / 5);
    }

    public double calculateHeatIndex() {
        return 0.5 * (temperature + 61.0 + ((temperature - 68.0) * 1.2) + (humidity * 0.094));
    }

    public double calculateWindChill() {
        // Simplified wind chill formula
        return 13.12 + 0.6215 * temperature - 11.37 * Math.pow(windVelocity, 0.16) + 0.3965 * temperature * Math.pow(windVelocity, 0.16);
    }
}"
