Thought: I will create a file `solution.py` containing the implementation. To handle recursive structures, I need to keep track of objects already visited during the conversion process to avoid infinite recursion. I'll use a `memo` dictionary to store the tuple representation of objects encountered.
<code>
content = """
import collections

def flatten_list(lst, memo=None):
    if memo is None: memo = {}
    if id(lst) in memo: return [] # Break recursion: return empty for self-ref
    memo[id(lst)] = True
    for i in lst:
        if isinstance(i, list):
            yield from flatten_list(i, memo)
        else:
            yield i

def convert_item(item, memo=None):
    if memo is None: memo = {}
    if id(item) in memo: return None # Marker for recursive ref

    if isinstance(item, list):
        memo[id(item)] = True
        return tuple(convert_item(i, memo.copy()) for i in flatten_list(item, memo.copy()))
    elif isinstance(item, dict):
        memo[id(item)] = True
        # Sort by keys
        sorted_items = sorted(item.items())
        return tuple((convert_item(k, memo.copy()), convert_item(v, memo.copy())) for k, v in sorted_items)
    else:
        return item

def count_frequency(lst):
    count_dict = collections.defaultdict(int)
    for item in lst:
        if isinstance(item, (list, dict)):
            # We use a fresh memo for each top-level item to allow same structure elsewhere
            tuple_item = convert_item(item, {})
            count_dict[tuple_item] += 1
    return dict(count_dict)

# Test cases
if __name__ == '__main__':
    test_data = [
        [1, 2], [1, 2], # Duplicate lists
        [[1, 2], 3], [1, 2, 3], # Nested vs Flat (should be same after flattening)
        {'a': 1, 'b': 2}, {'b': 2, 'a': 1}, # Duplicate dicts (diff order)
        'string', 123, # Should be ignored
    ]
    # Recursive structure
    rec = [1]
    rec.append(rec)
    test_data.append(rec)
    test_data.append(rec)

    print(count_frequency(test_data))
"""
