content = "import base64

class FormatError(Exception):
    pass

def analyze_b64_string(b64_str):
    try:
        # base64.b64decode handles both standard and urlsafe base64 in most cases,
        # but using urlsafe_b64decode explicitly or normalizing is safer.
        # For this implementation, we will try standard first then urlsafe.
        try:
            decoded_bytes = base64.b64decode(b64_str, altchars=b'-_')
        except Exception:
            decoded_bytes = base64.urlsafe_b64decode(b64_str)

        decoded_str = decoded_bytes.decode('utf-8')
    except Exception as e:
        raise FormatError(f'Unable to decode Base64: {e}')

    parts = decoded_str.split(',')

    if len(parts) != 4:
        raise FormatError("Decoded string format should be 'Name,Age,Gender,Occupation'")

    try:
        age = int(parts[1])
        if age < 0:
            raise FormatError("Age should be a non-negative integer")
    except ValueError:
        raise FormatError("Age should be an integer")

    gender = parts[2].lower()
    if gender not in ['male', 'female', 'non-binary', 'prefer not to say']:
        raise FormatError("Unrecognized gender")

    return {
        'Name': parts[0],
        'Age': age,
        'Gender': parts[2],
        'Occupation': parts[3]
    }

if __name__ == '__main__':
